import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"Запуск игры в IntelliJ IDEA","description":"Узнайте, как использовать различные профили запуска для запуска и отладки ваших модов в живой игровой среде с помощью IntelliJ IDEA.","frontmatter":{"title":"Запуск игры в IntelliJ IDEA","description":"Узнайте, как использовать различные профили запуска для запуска и отладки ваших модов в живой игровой среде с помощью IntelliJ IDEA.","authors":["IMB11","Tenneb22"],"prev":{"text":"Открытие проекта в IntelliJ IDEA","link":"./opening-a-project"},"next":{"text":"Генерация исходных текстов в IntelliJ IDEA","link":"./generating-sources"},"files":[]},"headers":[],"relativePath":"ru_ru/develop/getting-started/intellij-idea/launching-the-game.md","filePath":"translated/ru_ru/develop/getting-started/intellij-idea/launching-the-game.md","lastUpdated":1770561656000}`);var c={name:`ru_ru/develop/getting-started/intellij-idea/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Запуск игры в IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Запуск игры в IntelliJ IDEA”">​</a></h1><p>Fabric Loom предоставляет множество профилей запуска, чтобы помочь вам запустить и отладить мод в живой игровой среде. В этом руководстве мы расскажем о различных профилях запуска и о том, как использовать их для отладки и тестирования ваших модов.</p><h2 id="launch-profiles" tabindex="-1">Профили запуска <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “Профили запуска”">​</a></h2><p>Если вы используете IntelliJ IDEA, профили запуска можно найти в правом верхнем углу окна. Нажмите на выпадающее меню, чтобы просмотреть доступные профили запуска.</p><p>Там должен быть профиль клиента и сервера, с возможностью запуска в обычном режиме или в режиме отладки:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Профили запуска" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Задачи Gradle <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Задачи Gradle”">​</a></h2><p>Если вы используете командную строку, вы можете использовать следующие команды Gradle для запуска игры:</p><ul><li><code>./gradlew runClient</code> - Запуск игры в режиме клиента.</li><li><code>./gradlew runServer</code> - Запуск игры в режиме сервера.</li></ul><p>Единственная проблема с этим подходом заключается в том, что вы не можете легко отладить свой код. Если вы хотите отладить свой код, вам нужно будет использовать профили запуска в IntelliJ IDEA или через интеграцию Gradle в вашей IDE.</p><h2 id="hotswapping-classes" tabindex="-1">Классы «горячей замены» <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “Классы «горячей замены»”">​</a></h2><p>Когда вы запускаете игру в режиме отладки, вы можете производить горячую замену классов без перезапуска игры. Это полезно для быстрого тестирования изменений в коде.</p><p>Однако вы все еще ограничены:</p><ul><li>Вы не можете добавлять или удалять методы</li><li>Вы не можете изменить параметры метода</li><li>Вы не можете добавлять или удалять поля</li></ul><p>Однако, используя <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains Runtime</a>, вы можете обойти большинство ограничений и даже добавлять или удалять классы и методы. Это позволит большинству изменений вступить в силу без перезапуска игры.</p><p>Не забудьте добавить следующее в параметр VM Arguments в конфигурации запуска Minecraft:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">Горячая замена миксов <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “Горячая замена миксов”">​</a></h2><p>Если вы используете миксины, вы можете произвести горячую замену классов миксинов без перезапуска игры. Это полезно для быстрого тестирования изменений в ваших Mixins.</p><p>Однако для этого необходимо установить Java-агент Mixin.</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. Найдите Jar-файл библиотеки Mixin <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. Найдите Jar-файл библиотеки Mixin”">​</a></h3><p>В IntelliJ IDEA вы можете найти jar библиотеки mixin в разделе &quot;External Libraries&quot; секции &quot;Project&quot;:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin Library" loading="lazy"></p><p>Вам нужно скопировать «абсолютный путь» (Absolute Path) этого Jar-файла для следующего шага.</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. Добавьте аргумент <code>-javaagent</code> VM <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. Добавьте аргумент -javaagent VM”">​</a></h3><p>В конфигурации запуска &quot;Клиента Minecraft&quot; или &quot;Сервера Minecraft&quot; добавьте следующее в параметр VM Arguments:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;path to mixin library jar here&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="Скриншот VM Arguments" loading="lazy"></p><p>Теперь вы сможете изменять содержимое методов mixin во время отладки, и изменения вступят в силу без перезапуска игры.</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};